import React, { useState } from 'react';
import { Edit, Trash2, Eye, X, Plus, Users, Star, DollarSign, BookOpen, TrendingUp } from 'lucide-react';

const InstructorDashboard = ({ courses, onAddCourse, onUpdateCourse, onDeleteCourse }) => {
  const [showEditModal, setShowEditModal] = useState(false);
  const [showPreviewModal, setShowPreviewModal] = useState(false);
  const [showAddModal, setShowAddModal] = useState(false);
  const [selectedCourse, setSelectedCourse] = useState(null);
  const [courseForm, setCourseForm] = useState({
    title: '',
    desc: '',
    price: '',
    level: 'Beginner',
    cat: 'development',
    time: '',
    instructor: 'Current User',
    videoType: 'upload',
    videoFile: null,
    youtubeLink: '',
    dropboxLink: ''
  });

  const stats = {
    totalCourses: courses.length,
    totalStudents: courses.reduce((sum, course) => sum + course.enrolled, 0),
    totalRevenue: courses.reduce((sum, course) => sum + (course.price * course.enrolled), 0),
    avgRating: courses.length > 0 ? (courses.reduce((sum, course) => sum + parseFloat(course.rating), 0) / courses.length).toFixed(1) : '0.0'
  };

  const editCourse = (course) => {
    setSelectedCourse(course);
    setCourseForm({
      title: course.title,
      desc: course.desc,
      price: course.price.toString(),
      level: course.level,
      cat: course.cat,
      time: course.time,
      instructor: course.instructor,
      videoType: course.videoType || 'upload',
      videoFile: course.videoFile || null,
      youtubeLink: course.youtubeLink || '',
      dropboxLink: course.dropboxLink || ''
    });
    setShowEditModal(true);
  };

  const previewCourse = (course) => {
    setSelectedCourse(course);
    setShowPreviewModal(true);
  };

  const deleteCourse = (courseId, courseTitle) => {
    if (window.confirm(`Delete "${courseTitle}"?`)) {
      onDeleteCourse(courseId);
    }
  };

  const closeModal = (modalType) => {
    if (modalType === 'edit') {
      setShowEditModal(false);
    } else if (modalType === 'preview') {
      setShowPreviewModal(false);
    } else {
      setShowAddModal(false);
    }
    setSelectedCourse(null);
    setCourseForm({ title: '', desc: '', price: '', level: 'Beginner', cat: 'development', time: '', instructor: 'Current User', videoType: 'upload', videoFile: null, youtubeLink: '', dropboxLink: '' });
  };

  const handleFileUpload = (e) => {
    const file = e.target.files[0];
    if (file && file.type.startsWith('video/')) {
      setCourseForm({...courseForm, videoFile: file});
    }
  };

  const handleEditSubmit = (e) => {
    e.preventDefault();
    if (courseForm.title && courseForm.desc && courseForm.price && selectedCourse) {
      onUpdateCourse(selectedCourse.id, {
        ...selectedCourse,
        title: courseForm.title,
        desc: courseForm.desc,
        price: parseInt(courseForm.price),
        level: courseForm.level,
        cat: courseForm.cat,
        time: courseForm.time,
        instructor: courseForm.instructor,
        videoType: courseForm.videoType,
        videoFile: courseForm.videoFile,
        youtubeLink: courseForm.youtubeLink,
        dropboxLink: courseForm.dropboxLink
      });
      closeModal('edit');
    }
  };

  const handleAddSubmit = (e) => {
    e.preventDefault();
    if (courseForm.title && courseForm.desc && courseForm.price) {
      onAddCourse({
        title: courseForm.title,
        desc: courseForm.desc,
        price: parseInt(courseForm.price),
        level: courseForm.level,
        cat: courseForm.cat,
        time: courseForm.time,
        instructor: courseForm.instructor,
        img: 'https://images.unsplash.com/photo-1516321318423-f06f85e504b3?w=400&h=200&fit=crop',
        videoType: courseForm.videoType,
        videoFile: courseForm.videoFile,
        youtubeLink: courseForm.youtubeLink,
        dropboxLink: courseForm.dropboxLink
      });
      closeModal('add');
    }
  };

  return (
    <div style={{minHeight: '100vh', backgroundColor: '#f8fafc', padding: '2rem'}}>
      {/* Header */}
      <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem'}}>
        <div>
          <h1 style={{fontSize: '2.25rem', fontWeight: 'bold', color: '#1e293b'}}>Instructor Dashboard</h1>
          <p style={{color: '#64748b', marginTop: '0.5rem'}}>Manage your courses and track performance</p>
        </div>
        <button 
          onClick={() => setShowAddModal(true)}
          style={{backgroundColor: '#3b82f6', color: 'white', padding: '0.75rem 1.5rem', borderRadius: '0.5rem', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '0.5rem', fontSize: '1rem', fontWeight: '600'}}
        >
          <Plus style={{width: '1.25rem', height: '1.25rem'}} />
          Add Course
        </button>
      </div>

      {/* Stats Cards */}
      <div style={{display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))', gap: '1.5rem', marginBottom: '2rem'}}>
        <div style={{backgroundColor: 'white', padding: '1.5rem', borderRadius: '0.75rem', boxShadow: '0 4px 6px rgba(0,0,0,0.05)', border: '1px solid #e2e8f0'}}>
          <div style={{display: 'flex', alignItems: 'center', justifyContent: 'space-between'}}>
            <div>
              <p style={{color: '#64748b', fontSize: '0.875rem', marginBottom: '0.5rem'}}>Total Courses</p>
              <p style={{fontSize: '2rem', fontWeight: 'bold', color: '#1e293b'}}>{stats.totalCourses}</p>
            </div>
            <div style={{backgroundColor: '#dbeafe', padding: '0.75rem', borderRadius: '0.5rem'}}>
              <BookOpen style={{width: '1.5rem', height: '1.5rem', color: '#3b82f6'}} />
            </div>
          </div>
        </div>

        <div style={{backgroundColor: 'white', padding: '1.5rem', borderRadius: '0.75rem', boxShadow: '0 4px 6px rgba(0,0,0,0.05)', border: '1px solid #e2e8f0'}}>
          <div style={{display: 'flex', alignItems: 'center', justifyContent: 'space-between'}}>
            <div>
              <p style={{color: '#64748b', fontSize: '0.875rem', marginBottom: '0.5rem'}}>Total Students</p>
              <p style={{fontSize: '2rem', fontWeight: 'bold', color: '#1e293b'}}>{stats.totalStudents.toLocaleString()}</p>
            </div>
            <div style={{backgroundColor: '#dcfce7', padding: '0.75rem', borderRadius: '0.5rem'}}>
              <Users style={{width: '1.5rem', height: '1.5rem', color: '#16a34a'}} />
            </div>
          </div>
        </div>

        <div style={{backgroundColor: 'white', padding: '1.5rem', borderRadius: '0.75rem', boxShadow: '0 4px 6px rgba(0,0,0,0.05)', border: '1px solid #e2e8f0'}}>
          <div style={{display: 'flex', alignItems: 'center', justifyContent: 'space-between'}}>
            <div>
              <p style={{color: '#64748b', fontSize: '0.875rem', marginBottom: '0.5rem'}}>Total Revenue</p>
              <p style={{fontSize: '2rem', fontWeight: 'bold', color: '#1e293b'}}>₹{stats.totalRevenue.toLocaleString()}</p>
            </div>
            <div style={{backgroundColor: '#fef3c7', padding: '0.75rem', borderRadius: '0.5rem'}}>
              <DollarSign style={{width: '1.5rem', height: '1.5rem', color: '#d97706'}} />
            </div>
          </div>
        </div>

        <div style={{backgroundColor: 'white', padding: '1.5rem', borderRadius: '0.75rem', boxShadow: '0 4px 6px rgba(0,0,0,0.05)', border: '1px solid #e2e8f0'}}>
          <div style={{display: 'flex', alignItems: 'center', justifyContent: 'space-between'}}>
            <div>
              <p style={{color: '#64748b', fontSize: '0.875rem', marginBottom: '0.5rem'}}>Avg Rating</p>
              <p style={{fontSize: '2rem', fontWeight: 'bold', color: '#1e293b'}}>{stats.avgRating}</p>
            </div>
            <div style={{backgroundColor: '#f3e8ff', padding: '0.75rem', borderRadius: '0.5rem'}}>
              <Star style={{width: '1.5rem', height: '1.5rem', color: '#9333ea'}} />
            </div>
          </div>
        </div>
      </div>

      {/* Courses List */}
      <div style={{backgroundColor: 'white', borderRadius: '0.75rem', boxShadow: '0 4px 6px rgba(0,0,0,0.05)', border: '1px solid #e2e8f0', overflow: 'hidden'}}>
        <div style={{padding: '1.5rem', borderBottom: '1px solid #e2e8f0'}}>
          <h2 style={{fontSize: '1.5rem', fontWeight: 'bold', color: '#1e293b'}}>My Courses ({courses.length})</h2>
        </div>

        <div style={{padding: '1.5rem'}}>
          <div style={{display: 'flex', flexDirection: 'column', gap: '1rem'}}>
            {courses.map(course => (
              <div key={course.id} style={{backgroundColor: '#f8fafc', padding: '1.5rem', borderRadius: '0.5rem', border: '1px solid #e2e8f0'}}>
                <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center'}}>
                  <div style={{display: 'flex', alignItems: 'center', gap: '1rem'}}>
                    <img src={course.img} alt={course.title} style={{width: '4rem', height: '4rem', borderRadius: '0.5rem', objectFit: 'cover'}} />
                    <div>
                      <h3 style={{fontSize: '1.25rem', fontWeight: 'bold', color: '#1e293b', marginBottom: '0.25rem'}}>{course.title}</h3>
                      <p style={{color: '#64748b', marginBottom: '0.5rem'}}>{course.desc}</p>
                      <div style={{display: 'flex', alignItems: 'center', gap: '1rem', fontSize: '0.875rem'}}>
                        <span style={{color: '#16a34a', fontWeight: '600'}}>₹{course.price}</span>
                        <span style={{color: '#64748b'}}>{course.enrolled} students</span>
                        <span style={{color: '#d97706', display: 'flex', alignItems: 'center', gap: '0.25rem'}}>
                          <Star style={{width: '1rem', height: '1rem'}} />
                          {course.rating}
                        </span>
                        <span style={{backgroundColor: '#dbeafe', color: '#3b82f6', padding: '0.25rem 0.5rem', borderRadius: '0.25rem', fontSize: '0.75rem'}}>
                          {course.level}
                        </span>
                      </div>
                    </div>
                  </div>
                  <div style={{display: 'flex', gap: '0.5rem'}}>
                    <button 
                      onClick={() => editCourse(course)}
                      style={{padding: '0.5rem', color: '#3b82f6', backgroundColor: '#eff6ff', border: 'none', borderRadius: '0.375rem', cursor: 'pointer'}}
                      title="Edit Course"
                    >
                      <Edit style={{width: '1.25rem', height: '1.25rem'}} />
                    </button>
                    <button 
                      onClick={() => previewCourse(course)}
                      style={{padding: '0.5rem', color: '#16a34a', backgroundColor: '#ecfdf5', border: 'none', borderRadius: '0.375rem', cursor: 'pointer'}}
                      title="Preview Course"
                    >
                      <Eye style={{width: '1.25rem', height: '1.25rem'}} />
                    </button>
                    <button 
                      onClick={() => deleteCourse(course.id, course.title)}
                      style={{padding: '0.5rem', color: '#dc2626', backgroundColor: '#fef2f2', border: 'none', borderRadius: '0.375rem', cursor: 'pointer'}}
                      title="Delete Course"
                    >
                      <Trash2 style={{width: '1.25rem', height: '1.25rem'}} />
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Add Course Modal */}
      {showAddModal && (
