                <button 
                  type="button"
                  onClick={() => closeModal('edit')}
                  style={{backgroundColor: '#6b7280', color: 'white', padding: '0.75rem 1.5rem', borderRadius: '0.375rem', border: 'none', cursor: 'pointer', fontSize: '1rem'}}
